const items = $input.all();
const results = [];

const CATEGORY_TO_TYPE = {
  world_news: 'political_event',
  geopolitics: 'political_event',
  technology: 'technology',
  ai: 'technology',
  startups: 'company',
  venture_capital: 'company',
  business: 'company',
  economics: 'economic_event',
  hiring: 'economic_event',
  consumer: 'economic_event',
  regulation: 'government_body',
  law: 'government_body',
  cybersecurity: 'conflict_event',
  mergers_acquisitions: 'economic_event',
  research: 'technology',
  biotech: 'technology',
  marketing: 'company',
  sales: 'company',
  management: 'company',
  psychology: 'social_movement',
  science: 'technology',
  energy: 'commodity_flow',
  esg: 'economic_event',
  crypto: 'financial_instrument',
  supply_chain: 'supply_chain',
};

const CATEGORY_TO_CAUSAL = {
  world_news:           { causal_weight: 0.4, mechanism: 'news_signal' },
  geopolitics:          { causal_weight: 0.6, mechanism: 'geopolitical_analysis' },
  technology:           { causal_weight: 0.3, mechanism: 'tech_signal' },
  ai:                   { causal_weight: 0.5, mechanism: 'tech_signal' },
  startups:             { causal_weight: 0.5, mechanism: 'startup_signal' },
  venture_capital:      { causal_weight: 0.7, mechanism: 'funding_event' },
  business:             { causal_weight: 0.4, mechanism: 'business_signal' },
  economics:            { causal_weight: 0.6, mechanism: 'macro_signal' },
  hiring:               { causal_weight: 0.6, mechanism: 'labour_market_signal' },
  consumer:             { causal_weight: 0.8, mechanism: 'inflation_signal' },
  regulation:           { causal_weight: 0.7, mechanism: 'regulatory_signal' },
  law:                  { causal_weight: 0.7, mechanism: 'regulatory_signal' },
  cybersecurity:        { causal_weight: 0.6, mechanism: 'cyber_threat' },
  mergers_acquisitions: { causal_weight: 0.8, mechanism: 'ma_signal' },
  research:             { causal_weight: 0.4, mechanism: 'research_signal' },
  biotech:              { causal_weight: 0.4, mechanism: 'research_signal' },
  energy:               { causal_weight: 0.8, mechanism: 'energy_supply_signal' },
  crypto:               { causal_weight: 0.5, mechanism: 'crypto_signal' },
  supply_chain:         { causal_weight: 0.6, mechanism: 'supply_chain_signal' },
};

// Extract named entities from text (simple heuristic: capitalised multi-word phrases)
function extractMentions(text) {
  const matches = text.match(/\b([A-Z][a-z]+ (?:[A-Z][a-z]+ ?){0,2})\b/g) || [];
  return [...new Set(matches)].slice(0, 5);
}

for (const item of items) {
  const a = item.json;
  if (!a.title || !a.source) continue;

  const title = a.title.trim();
  const category = a.category || 'world_news';
  const source = a.source;
  const url = a.link || a.url || '';
  const published = a.pubDate || a.isoDate || new Date().toISOString();

  const description = (a.content || a.contentSnippet || a.summary || '')
    .replace(/<[^>]*>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"')
    .substring(0, 800);

  const entityType = CATEGORY_TO_TYPE[category] || 'political_event';
  const causal = CATEGORY_TO_CAUSAL[category] || { causal_weight: 0.3, mechanism: 'news_signal' };

  // Build relationships: link to the source organisation and any mentioned entities
  const relationships = [
    {
      targetName: source,
      targetType: 'company',
      targetProperties: { domain: 'media', category },
      relation: 'cited_by',
      confidence: 0.9,
      causal_weight: 0.1,
      mechanism: 'media_attribution',
    }
  ];

  // Extract mentioned organisations/people and link them
  const mentions = extractMentions(title + ' ' + description.substring(0, 200));
  for (const mention of mentions) {
    if (mention === title.substring(0, mention.length)) continue; // skip self
    relationships.push({
      targetName: mention,
      targetType: 'person',
      relation: 'related_to',
      confidence: 0.4,
      causal_weight: causal.causal_weight * 0.5,
      mechanism: causal.mechanism,
    });
  }

  results.push({
    json: {
      name: title.substring(0, 200),
      type: entityType,
      properties: {
        url,
        description: description.substring(0, 500),
        category,
        published,
      },
      relationships,
      source,
      confidence: 0.7,
      causal_weight: causal.causal_weight,
      mechanism: causal.mechanism,
    }
  });
}

return results.length > 0 ? results : [{ json: null }];

const items = $input.all().filter(i => i.json !== null);
const BATCH_SIZE = 25;
const batches = [];

for (let i = 0; i < items.length; i += BATCH_SIZE) {
  const batch = items.slice(i, i + BATCH_SIZE).map(item => item.json);
  batches.push({ json: { batch } });
}

return batches.length > 0 ? batches : [{ json: { batch: [] } }];

const items = $input.all();
for (const item of items) {
  if (item.json.error || (item.json.statusCode && item.json.statusCode >= 400)) {
    console.error('[Graph POST Error]', JSON.stringify(item.json));
  } else {
    const accepted = item.json.accepted_count || '?';
    console.log(`[Graph POST OK] Batch accepted: ${accepted} entities`);
  }
}
return items;
